// --- 3. Unified Data Model ---

/// The unified data model (Memory) for the CDQN agent.
#[derive(Debug, Clone)]
pub enum CausalDataUnit {
    Task(TaskCdu),
    Step(StepCdu),
    Path(PathCdu),
    Axiom(AxiomCdu),
    Ko(KoCdu),
    Ok(OkCdu),
}

// Helper trait for easy ID generation on any CDU variant
pub trait Identifiable {
    fn id(&self) -> HlcId;
    fn new_id() -> HlcId;
}

impl Identifiable for CausalDataUnit {
    fn id(&self) -> HlcId {
        match self {
            CausalDataUnit::Task(t) => t.id,
            CausalDataUnit::Step(s) => s.id,
            CausalDataUnit::Path(p) => p.id,
            CausalDataUnit::Axiom(a) => a.id,
            CausalDataUnit::Ko(k) => k.id,
            CausalDataUnit::Ok(o) => o.id,
        }
    }
    
    // This is a placeholder. In a real system, ID generation would be handled
    // by the ChronosAgent's Memory Manager role to ensure proper clock state.
    fn new_id() -> HlcId {
        HlcId::new()
    }
}

